local function Get(self, num, ...) local inst = self.inst local obj = self.dycOldGet(self, num, ...) if obj ~= inst then local encs = inst:GetEnchantments() for k, v in pairs(encs) do obj:AddEnchantment(k) end end return obj end local function Put(self, item, source_pos, ...) local inst = self.inst if inst and item and inst ~= item then local encs = item:GetEnchantments() for k, v in pairs(encs) do if inst:GetEnchantmentCount(nil, { "noscrap" , "legendary" }) < 0x4 then inst:AddEnchantment(k) else break end end end local ret = self.dycOldPut(self, item, source_pos, ...) return ret end local function DYCStackable(self) self.dycOldGet = self.Get self.Get = Get self.dycOldPut = self.Put self.Put = Put end return DYCStackable 